201: 	Gather() ([]*dto.MetricFamily, error)
202: 	// Reset invokes the Reset() function on all items in the registry
203: 	// which are added as resettables.
204: 	Reset()
205: 	// RegisterMetaMetrics registers metrics about the number of registered metrics.
206: 	RegisterMetaMetrics()
207: 	// Registerer exposes the underlying prometheus registerer
208: 	Registerer() prometheus.Registerer
